import { Injectable, HttpStatus } from '@nestjs/common';
import { InjectModel } from 'nestjs-dynamoose';
import type { Model } from 'nestjs-dynamoose';
import { Bundles, BundleKey } from './bundles.interface';
import { v7 as uuidv7 } from 'uuid'

@Injectable()
export class BundlesService {
    constructor(
        @InjectModel('Bundle')
        private bundleModel: Model<Bundles, BundleKey>
    ) { }

    create(bundle: Bundles) {

        bundle.bundleId = uuidv7(); // Simple ID generation
        bundle.creationDate = Date.now();
        bundle.bundleStatus = "ACTIVE";
        return this.bundleModel.create(bundle);
    }

    findAll(limit?: number, page?: number) {
        console.log('Service received - limit:', limit, 'type:', typeof limit, 'page:', page, 'type:', typeof page);
        const finalLimit = limit !== undefined ? Number(limit) : 10;
        const finalPage = page !== undefined ? Number(page) : 1;
        const scan = this.bundleModel.scan();
        const itemsToSkip = (finalPage - 1) * finalLimit;

        scan.limit(finalLimit + itemsToSkip);

        return scan.exec().then(results => {
            const paginatedItems = results.slice(itemsToSkip, itemsToSkip + finalLimit);
            return {
                items: paginatedItems,
                page: finalPage,
                limit: finalLimit,
                total: results.count
            };
        });
    }

    findOne(id: string) {
        return this.bundleModel.query('bundleId').eq(id).exec();
    }

    async update(id: string, bundle: Bundles) {
        console.log("Trying to update bundle:", id, bundle);
        const result = await this.findOne(id);

        if (result.count === 0) {
            console.log('Bundle not found');
            return { statusCode: HttpStatus.NOT_FOUND, error: 'Bundle not found' } as any;
        }

        const updateData: any = {
            lastUpdate: Date.now()
        };
        if (bundle.bundleName !== undefined) updateData.bundleName = bundle.bundleName;
        if (bundle.bundleDescription !== undefined) updateData.bundleDescription = bundle.bundleDescription;
        if (bundle.bundleContentsId !== undefined) updateData.bundleContentsId = bundle.bundleContentsId;

        return this.bundleModel.update({ bundleId: id }, updateData);
    }

    async delete(id: string): Promise<any> {
        const result = await this.findOne(id);

        if (result.length === 0) {
            return { statusCode: HttpStatus.NOT_FOUND, error: 'Bundle not found' };
        }

        return this.bundleModel.update(
            { bundleId: id },
            {
                bundleStatus: 'INACTIVE',
                lastUpdate: Date.now()
            }
        );
    }
}

