import { Injectable, HttpStatus } from '@nestjs/common';
import { InjectModel } from 'nestjs-dynamoose';
import type { Model } from 'nestjs-dynamoose';
import { Contents, ContentKey } from './contents.interface';
import { v7 as uuidv7 } from 'uuid'

@Injectable()
export class ContentsService {
    constructor(
        @InjectModel('Content')
        private contentModel: Model<Contents, ContentKey>
    ) { }

    create(content: Contents) {
        content.contentId = uuidv7(); // Simple ID generation
        content.creationDate = Date.now();
        content.contentStatus = "ACTIVE";
        content.contentMetadata = JSON.stringify(content.contentMetadata) || "{}";
        return this.contentModel.create(content);
    }

    private parseMetadata(content: any) {
        if (content.contentMetadata) {
            try {
                content.contentMetadata = JSON.parse(content.contentMetadata);
            } catch (e) {
                // Keep as string if not parseable
            }
        }
        return content;
    }

    findAll(limit?: number, page?: number) {
        const finalLimit = limit || 10;
        const finalPage = page || 1;
        const scan = this.contentModel.scan();
        const itemsToSkip = (finalPage - 1) * finalLimit;

        scan.limit(finalLimit + itemsToSkip);

        return scan.exec().then(results => {
            const paginatedItems = results.slice(itemsToSkip, itemsToSkip + finalLimit).map(item => this.parseMetadata(item));
            return {
                items: paginatedItems,
                page: finalPage,
                limit: finalLimit,
                total: results.count
            };
        });
    }

    findOne(id: string) {
        return this.contentModel.query('contentId').eq(id).exec().then(results => results.map(item => this.parseMetadata(item)));
    }

    async update(id: string, content: Contents): Promise<any> {
        console.log("Updating content:", id, content);
        const existing = await this.findOne(id);

        if (existing.length === 0) {
            return { statusCode: HttpStatus.NOT_FOUND, error: 'Content not found' };
        }

        return this.contentModel.update(
            { contentId: id }, 
            { 
                contentName: content.contentName, 
                contentDescription: content.contentDescription, 
                lastUpdate: Date.now() 
            }
        );
    }

    async delete(id: string): Promise<any> {
        const existing = await this.findOne(id);

        if (existing.length === 0) {
            return { statusCode: HttpStatus.NOT_FOUND, error: 'Content not found' };
        }

        return this.contentModel.update(
            { contentId: id }, 
            { 
                contentStatus: 'INACTIVE',
                lastUpdate: Date.now() 
            }
        );
    }
}

