import { Injectable, HttpStatus } from '@nestjs/common';
import { InjectModel } from 'nestjs-dynamoose';
import type { Model } from 'nestjs-dynamoose';
import { Contracts, ContractKey, VendorSubscriptionData } from './contracts.interface';
import { v7 as uuidv7 } from 'uuid'


@Injectable()
export class ContractsService {
    constructor(
        @InjectModel('Contract')
        private contractModel: Model<Contracts, ContractKey>
    ) { }

    private generateSubscriptionBundleKey(subscriptionId: string, bundleId: string): string {
        return `${subscriptionId}#${bundleId}`;
    }

    async checkDuplicate(subscriptionBundleKey: string) {
        const result = await this.contractModel.query('contractSubscriptionBundleKey')
            .eq(subscriptionBundleKey)
            .using('SubscriptionBundleIndex')
            .exec();
        const activeContract = result.find(contract => contract.contractStatus === 'ACTIVE');
        return activeContract || null;
    }

    async create(contract: Contracts) {
        contract.contractId = uuidv7();
        contract.creationDate = Date.now();
        contract.contractStatus = "ACTIVE";
        contract.contractCustomFields = JSON.stringify(contract.contractCustomFields) || "{}";

        console.log("Atempting to create contract:", contract)

        if (contract.contractExternalSubscriberId && contract.contractBundleId) {
            contract.contractSubscriptionBundleKey = this.generateSubscriptionBundleKey(
                contract.contractExternalSubscriberId,
                contract.contractBundleId
            );

            const isDuplicate = await this.checkDuplicate(contract.contractSubscriptionBundleKey);
            if (isDuplicate) {
                return ({ 
                    statusCode: HttpStatus.CONFLICT,
                    error: 'Contract with this subscription and bundle combination already exists', 
                    existingContract: isDuplicate 
                });
            }
        }

        return this.contractModel.create(contract);
    }

    findAll(limit?: number, page?: number) {
        const finalLimit = limit !== undefined ? Number(limit) : 10;
        const finalPage = page !== undefined ? Number(page) : 1;
        const scan = this.contractModel.scan();
        const itemsToSkip = (finalPage - 1) * finalLimit;

        scan.limit(finalLimit + itemsToSkip);

        return scan.exec().then(results => {
            const paginatedItems = results.slice(itemsToSkip, itemsToSkip + finalLimit);
            return {
                items: paginatedItems,
                page: finalPage,
                limit: finalLimit,
                total: results.count
            };
        });
    }

    findOne(id: string) {
        return this.contractModel.query('contractId').eq(id).exec();
    }


    findByVendorAndSubscription(data: VendorSubscriptionData) {
        console.log("Finding by vendor and subscription:", data.contractVendorId, data.contractExternalSubscriberId);
        console.log(`${data.contractVendorId}${data.contractExternalSubscriberId}`)
        return this.contractModel.query('contractVendorId').eq(data.contractVendorId).where('contractExternalSubscriberId').eq(data.contractExternalSubscriberId).using('VendorSubscriptionIndex').exec();
    }

    disableEntitlementByVendorSubscription(data: object) {
        return this.findByVendorAndSubscription(data as VendorSubscriptionData).then((result) => {
            if (result.length === 0) {
                return { statusCode: HttpStatus.NOT_FOUND, error: 'Contract not found for given vendor and subscription' };
            }

            const existing = result[0];
            if (!existing.contractEntitlement) {
                console.log("Entitlement already disabled for contract:", existing.contractId);
                return { statusCode: HttpStatus.OK, data: existing } as any;
            }
            return this.contractModel.update(
                { contractId: existing.contractId, contractVendorId: existing.contractVendorId },
                {
                    contractEntitlement: false,
                    lastUpdate: Date.now()
                }
            );
        });
    }

    enableEntitlementByVendorSubscription(data: object) {
        return this.findByVendorAndSubscription(data as VendorSubscriptionData).then((result) => {
            if (result.length === 0) {
                return { statusCode: HttpStatus.NOT_FOUND, error: 'Contract not found for given vendor and subscription' };
            }

            const existing = result[0];
            if (existing.contractEntitlement) {
                console.log("Entitlement already enabled for contract:", existing.contractId);
                return { statusCode: HttpStatus.OK, data: existing } as any;
            }
            return this.contractModel.update(
                { contractId: existing.contractId, contractVendorId: existing.contractVendorId },
                {
                    contractEntitlement: true,
                    lastUpdate: Date.now()
                }
            );
        });
    }

    delete(id: string) {
        return this.findOne(id).then((result) => {
            if (result.length === 0) {
                return { statusCode: HttpStatus.NOT_FOUND, error: 'Contract not found' } as any;
            }

            const existing = result[0];
            return this.contractModel.update(
                { contractId: id, contractVendorId: existing.contractVendorId },
                {
                    contractStatus: 'INACTIVE',
                    lastUpdate: Date.now()
                }
            );
        });
    }
}

